-- Bookrary Manga Dataset Seeds (100 Titles)
-- Location: Database/seeds/mangaSeed.sql

ON DUPLICATE KEY UPDATE title=VALUES(title), author=VALUES(author), coverImage=VALUES(coverImage), bannerImage=VALUES(bannerImage), synopsis=VALUES(synopsis), totalVolumes=VALUES(totalVolumes), status=VALUES(status), category=VALUES(category), genres=VALUES(genres), likeAmount=VALUES(likeAmount), dislikeAmount=VALUES(dislikeAmount), favoriteAmount=VALUES(favoriteAmount), rating=VALUES(rating);
